int _rsa(int type)
{
    int ret;
    mbedtls_rsa_context rsa;
    mbedtls_mpi N, E;

    LOG_INF("===== RSA Certificate Authentication =====");

    mbedtls_rsa_init(&rsa);
    mbedtls_mpi_init(&N);
    mbedtls_mpi_init(&E);

    mbedtls_mpi_read_binary(&N, RSA_N, 512);
    mbedtls_mpi_read_binary(&E, RSA_E, 3);

    ret = mbedtls_rsa_import(&rsa, &N, NULL, NULL, NULL, &E);
    if (ret != 0) {
        LOG_ERR("rsa_import failed %d", ret);
        return ret;
    }

    uint8_t hash[32];
    mbedtls_sha256(VERIFY_DATA, sizeof(VERIFY_DATA), hash, 0);

    LOG_INF("Verifying signature...");
    ret = mbedtls_rsa_pkcs1_verify(&rsa,
                                   MBEDTLS_MD_SHA256,
                                   32,
                                   hash,
                                   RSA_SIGNATURE);

    if (ret == 0) {
        LOG_INF("Verification successful = Certificate valid, identity trusted");
    } else {
        LOG_ERR("Verification failed = Certificate forged / data tampered");
    }

    mbedtls_rsa_free(&rsa);
    mbedtls_mpi_free(&N);
    mbedtls_mpi_free(&E);
    return ret;
}